previewCss:
.darma-loader-darma-custom-613 {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   width: 82px;
   aspect-ratio: 1;
   padding: 10px;
   box-sizing: border-box;
   display: grid;
   background: currentColor;
   filter: blur(5px) contrast(10);
   mix-blend-mode: darken;
}
.darma-loader-darma-custom-613:before, .darma-loader-darma-custom-613:after {
  content: "";
   grid-area: 1/1;
   background: linear-gradient(currentColor 0 0) left, linear-gradient(currentColor 0 0) right;
   background-size: 20px 40px;
   background-origin: content-box;
   background-repeat: no-repeat;
}
.darma-loader-darma-custom-613:after  {
  height: 20px;
   width: 20px;
   margin: auto 0;
   border-radius: 50%;
   background: currentColor;
   animation: darma-loader-darma-custom-613-l10 1s infinite;
}
@keyframes darma-loader-darma-custom-613-l10 {
  90%,100% {transform: translate(300%)}
}

